import{_ as r,o as e,c as a,a5 as o}from"./chunks/framework.B5tqjWbr.js";const p=JSON.parse('{"title":"学习记录 #0010：单相逆变器控制——UPS的输出级","description":"","frontmatter":{"date":"2026-06-14T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"学习记录 #0010：单相逆变器控制——UPS的输出级","tags":["power-electronics"],"status":"learning","summary":"**日期**：2026-06-13 **课程**：第10课 — 单相逆变器控制（Phase 2核心拓扑） **状态**：进行中"},"headers":[],"relativePath":"content/power/archive/old-learning-records/0010-single-phase-inverter.md","filePath":"content/power/archive/old-learning-records/0010-single-phase-inverter.md","lastUpdated":null}'),n={name:"content/power/archive/old-learning-records/0010-single-phase-inverter.md"};function s(i,t,l,c,d,g){return e(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="学习记录-0010-单相逆变器控制——ups的输出级" tabindex="-1">学习记录 #0010：单相逆变器控制——UPS的输出级 <a class="header-anchor" href="#学习记录-0010-单相逆变器控制——ups的输出级" aria-label="Permalink to &quot;学习记录 #0010：单相逆变器控制——UPS的输出级&quot;">​</a></h1><p><strong>日期</strong>：2026-06-13 <strong>课程</strong>：第10课 — 单相逆变器控制（Phase 2核心拓扑） <strong>状态</strong>：进行中</p><h2 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h2><ol><li><strong>全桥逆变器</strong>：4个开关管，4种开关状态（+Vdc/-Vdc/0续流x2）</li><li><strong>LC滤波器</strong>：fr=1/(2π√LC)，设计范围500Hz&lt;fr&lt;1600Hz，阻尼比极低（0.01~0.05）</li><li><strong>双闭环必要性</strong>：电流内环提供LC谐振峰有源阻尼，电压外环稳定输出电压</li><li><strong>PR控制器</strong>：在谐振频率ω0处增益无穷大→交流无静差，是&quot;交流版的PI&quot;</li><li><strong>准PR</strong>：加入ωc截止频率增加鲁棒性，Tustin离散化为二阶IIR</li><li><strong>谐波补偿PR</strong>：并联3/5/7次PR，选择性放大特定谐波频率</li><li><strong>单极性SPWM</strong>：等效频率2×fsw、dv/dt减半、THD更低、EMI更小</li><li><strong>负载电流前馈</strong>：突加负载时立即补偿，Vout跌落从几十ms缩短到几ms</li><li><strong>电机对照</strong>：UPS=电压源（PR），电机=电流源（dq+PI），硬件相同控制不同</li></ol><h2 id="待深入问题" tabindex="-1">待深入问题 <a class="header-anchor" href="#待深入问题" aria-label="Permalink to &quot;待深入问题&quot;">​</a></h2><ul><li>[ ] LCL滤波器比LC好在哪里？谐振怎么抑制？</li><li>[ ] 逆变器带整流负载时THD为什么很高？怎么解决？</li><li>[ ] PIR控制器中I项的作用是什么？</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>进入第11课：三相逆变器控制</p>',8)])])}const u=r(n,[["render",s]]);export{p as __pageData,u as default};
